Literal.Value:
'{
  "description": "Clientes por Região — dCliente[REGIAO] + _Medidas[Total Clientes]",
  "data": { "name": "dataset" },
  "width": "container",
  "height": "container",
  "background": "transparent",
  "transform": [
    { "joinaggregate": [{ "op": "sum", "field": "Total Clientes", "as": "tot" }] },
    { "calculate": "datum[''Total Clientes''] / datum.tot", "as": "pct" },
    { "calculate": "format(datum[''Total Clientes''], '',.0f'') + ''  ·  '' + format(datum.pct, ''.0%'')", "as": "rotulo" }
  ],
  "title": {
    "text": "Clientes por Região",
    "subtitle": "Distribuição da base",
    "anchor": "start",
    "color": "#ffffff",
    "fontSize": 15,
    "fontWeight": 600,
    "subtitleColor": "#8888A8",
    "subtitleFontSize": 11,
    "subtitlePadding": 4,
    "offset": 6,
    "dx": 2
  },
  "encoding": {
    "y": {
      "field": "REGIAO",
      "type": "nominal",
      "sort": { "field": "Total Clientes", "order": "descending" },
      "title": null,
      "axis": { "labelColor": "#e5e7eb", "domainColor": "transparent", "tickColor": "transparent", "labelFontSize": 12 }
    },
    "x": {
      "field": "Total Clientes",
      "type": "quantitative",
      "title": null,
      "axis": { "labels": false, "grid": false, "domainColor": "transparent", "tickColor": "transparent" }
    }
  },
  "layer": [
    {
      "mark": { "type": "bar", "cornerRadiusEnd": 6, "height": 16 },
      "params": [
        { "name": "sel", "select": { "type": "point", "on": "click", "fields": ["REGIAO"], "clear": "dblclick" } }
      ],
      "encoding": {
        "color": {
          "field": "Total Clientes",
          "type": "quantitative",
          "scale": { "range": ["rgba(139,92,246,0.30)", "#8B5CF6"] },
          "legend": null
        },
        "tooltip": [
          { "field": "REGIAO", "type": "nominal", "title": "Região" },
          { "field": "Total Clientes", "type": "quantitative", "title": "Clientes", "format": ",.0f" },
          { "field": "pct", "type": "quantitative", "title": "Participação", "format": ".1%" }
        ]
      }
    },
    {
      "mark": { "type": "text", "align": "left", "dx": 6, "color": "#9ca3af", "fontSize": 11 },
      "encoding": { "text": { "field": "rotulo", "type": "nominal" } }
    }
  ],
  "config": { "view": { "stroke": "transparent" } }
}'
